class Playground {
    async run(inputs) {
        let treeData;
        try {
            treeData = JSON.parse(inputs[0]);
        } catch (e) {
            this.log("Invalid input format. Please provide a JSON array.");
            return null;
        }

        // 1. Initialize data structures
        this.tree.init(treeData);
        this.callstack.init();
        this.recursionTree.init();
        this.traversalOrder.init([]);

        const root = this.tree.getRoot();

        if (!root) {
            this.log("Tree is empty.");
            return [];
        }

        const result = [];

        // 2. Define Recursive DFS function
        const dfs = async (node) => {
            if (!node) return;

            // --- ENTERING NODE ---
            const nodeId = node.id;
            const nodeVal = node.val;

            // Push frame to call stack and enter recursion tree
            this.callstack.pushFrame("dfs", { val: nodeVal });
            this.recursionTree.enterNode(nodeId, nodeVal.toString());

            // Highlight the current node in the binary tree
            this.tree.highlight(nodeId, "#00e0ff"); // Current node color
            this.log(`Visiting Node: ${nodeVal}`);

            // Process current node (Pre-order: Root first)
            result.push(nodeVal);
            this.traversalOrder.push(nodeVal);
            this.traversalOrder.highlight(result.length - 1, "#00f5a0");

            await this.await();

            // --- RECURSE LEFT ---
            if (node.left) {
                this.log(`Moving Left from ${nodeVal}`);
                await dfs(node.left);
            } else {
                this.log(`No left child for ${nodeVal}`);
                // Optional: visualize null child check
                this.callstack.pushFrame("dfs", { val: "null" });
                await this.await();
                this.callstack.popFrame();
            }

            // --- RECURSE RIGHT ---
            if (node.right) {
                this.log(`Moving Right from ${nodeVal}`);
                await dfs(node.right);
            } else {
                this.log(`No right child for ${nodeVal}`);
                this.callstack.pushFrame("dfs", { val: "null" });
                await this.await();
                this.callstack.popFrame();
            }

            // --- EXITING NODE ---
            this.log(`Finished processing node ${nodeVal}, returning...`);
            this.tree.highlight(nodeId, "#00f5a0"); // Mark as completed/visited

            this.callstack.popFrame(nodeVal);
            this.recursionTree.exitNode();
            await this.await();
        };

        // 3. Start traversal
        await dfs(root);

        this.log("DFS Traversal Complete!");
        return result;
    }
}
